<div class="card"><div class="card-head between"><h3>Manage Users</h3><form method="get" action="<?= base_url('index.php') ?>" class="inline-form"><input type="hidden" name="route" value="admin/users"><input type="text" name="search" placeholder="Search users" value="<?= e($search) ?>"><button class="btn btn-outline btn-sm">Search</button></form></div><div class="table-wrap"><table><thead><tr><th>Name</th><th>Email</th><th>Username</th><th>Balance</th><th>Status</th><th>Action</th></tr></thead><tbody><?php foreach ($users as $u): ?><tr><td><?= e($u['name']) ?></td><td><?= e($u['email']) ?></td><td><?= e($u['username']) ?></td><td><?= money((float)$u['balance']) ?></td><td><span class="badge"><?= e($u['status']) ?></span></td><td><?php if ($u['role'] !== 'admin'): ?><form method="post" action="<?= base_url('index.php?route=admin/users/toggle-status') ?>" class="inline-form"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><input type="hidden" name="id" value="<?= (int)$u['id'] ?>"><input type="hidden" name="status" value="<?= $u['status'] === 'active' ? 'inactive' : 'active' ?>"><button class="btn btn-sm <?= $u['status'] === 'active' ? 'btn-danger' : 'btn-primary' ?>" type="submit"><?= $u['status'] === 'active' ? 'Deactivate' : 'Activate' ?></button></form><?php else: ?>Admin<?php endif; ?></td></tr><?php endforeach; ?><?php if (!$users): ?><tr><td colspan="6">No users found.</td></tr><?php endif; ?></tbody></table></div></div>
